class Solution {
    public long countGoodIntegers(int n, int k) {
        if (n == 1) {
            return (9 / k);
        }
        long res = 0;
        for (int i = (int) Math.pow(10, n - 1); i < Math.pow(10, n); i++) {
            int[] count = new int[10];
            boolean isGood = true;
            int num = i;
            while (num > 0) {
                count[num % 10]++;
                num /= 10;
            }
            int[] arr = new int[n];
            int idx = 0;
            for (int j = 0; j < 10; j++) {
                while (count[j] > 0) {
                    arr[idx++] = j;
                    count[j]--;
                }
            }
            for (int j = 0; j < n / 2; j++) {
                if (arr[j] != arr[n - j - 1]) {
                    isGood = false;
                    break;
                }
            }
            if (isGood && i % k == 0) {
                res++;
            }
        }
        return res;
    }
}
